1	//! The `config` subcommand: print the settable config schema,
2	//! grouped by config home then TOML section, sshd_config style.
3	//!
4	//! Read-only; consumes `crate::config_schema::schema()` — the
5	//! single source of truth for every settable key. `--home` filters
6	//! which home group(s) are printed.
7	
8	use std::error::Error;
9	
10	use clap::{Args, ValueEnum};
11	
12	use log::{info, warn};
13	
14	use crate::common::find_workspace_root;
15	use crate::config::config_path;
16	use crate::config_schema::{ConfigKey, Home, render_key_block, schema, section_and_leaf};
17	use crate::context::Context;
18	use crate::desc_helpers::VC_CONFIG_FILE;
19	use crate::subcommand::SubcommandRunner;
20	use crate::toml_simple::toml_load;
21	
22	/// Which config home(s) to print.
23	#[derive(Clone, Copy, Debug, PartialEq, Eq, ValueEnum)]
24	#[value(rename_all = "kebab-case")]
25	pub enum HomeFilter {
26	    /// Only the user config (`~/.config/vc-x1/config.toml`).
27	    User,
28	    /// Only the workspace config (`<root>/.vc-config.toml`).
29	    Workspace,
30	    /// Both homes (default).
31	    All,
32	}
33	
34	#[derive(Args, Debug)]
35	pub struct ConfigArgs {
36	    /// Which config home(s) to print: user, workspace, or all
37	    #[arg(long, value_enum, default_value_t = HomeFilter::All)]
38	    pub home: HomeFilter,
39	
40	    /// Check the config file(s) for unknown/misspelled keys instead
41	    /// of printing the schema
42	    #[arg(long)]
43	    pub validate: bool,
44	}
45	
46	/// Inputs to the `config` op, flat, owned, clap-free.
47	///
48	/// Mirrors `ConfigArgs`: `--home` (`home`), `--validate` (`validate`).
49	pub struct ConfigParams {
50	    pub home: HomeFilter,
51	    pub validate: bool,
52	}
53	
54	impl From<&ConfigArgs> for ConfigParams {
55	    /// Convert clap-derived `ConfigArgs` into the flat
56	    /// `ConfigParams` (total — every field copies straight over).
57	    fn from(a: &ConfigArgs) -> Self {
58	        Self {
59	            home: a.home,
60	            validate: a.validate,
61	        }
62	    }
63	}
64	
65	impl SubcommandRunner for ConfigArgs {
66	    type Params = ConfigParams;
67	
68	    /// Delegate to the existing `From<&ConfigArgs>` impl above
69	    /// (total — never fails).
70	    fn to_params(&self) -> Result<Self::Params, String> {
71	        Ok(ConfigParams::from(self))
72	    }
73	
74	    /// Run the `config` op.
75	    fn run(ctx: &Context, params: &Self::Params) -> Result<(), Box<dyn std::error::Error>> {
76	        config(ctx, params)
77	    }
78	}
79	
80	/// A key belongs to the User group if any of its homes is
81	/// `Home::User`.
82	fn in_user_group(key: &ConfigKey) -> bool {
83	    key.homes.contains(&Home::User)
84	}
85	
86	/// A key belongs to the Workspace group if any of its homes is
87	/// `Home::WorkspaceCode` or `Home::WorkspaceBot`.
88	fn in_workspace_group(key: &ConfigKey) -> bool {
89	    key.homes.contains(&Home::WorkspaceCode) || key.homes.contains(&Home::WorkspaceBot)
90	}
91	
92	/// Print one home group: a divider, then each key grouped by
93	/// section (schema order, first-seen section order), one
94	/// `[section]` header per section. Each key renders as a
95	/// multi-line doc-block via `render_key_block` (shared with
96	/// `crate::init`'s generated `.vc-config.toml`).
97	fn print_group(title: &str, path_hint: &str, keys: &[&ConfigKey]) {
98	    info!("# ── {title} config: {path_hint} ──");
99	    let mut sections: Vec<&str> = Vec::new();
100	    for key in keys {
101	        let (section, _leaf) = section_and_leaf(key.path);
102	        if !sections.contains(&section) {
103	            sections.push(section);
104	        }
105	    }
106	    for section in sections {
107	        info!("[{section}]");
108	        for key in keys {
109	            let (key_section, _leaf) = section_and_leaf(key.path);
110	            if key_section != section {
111	                continue;
112	            }
113	            for line in render_key_block(key).lines() {
114	                info!("{line}");
115	            }
116	        }
117	    }
118	    info!("");
119	}
120	
121	/// True if `actual` (a config key from a loaded config file) is
122	/// recognized by some `schema()` entry whose homes satisfy
123	/// `home_pred`.
124	///
125	/// - Non-dynamic entries match by exact path equality.
126	/// - Dynamic entries (`key.dynamic`) match segment-wise: equal
127	///   segment counts, each entry segment either equal to the actual
128	///   segment or a `<placeholder>` matching any single segment.
129	fn key_known(actual: &str, home_pred: impl Fn(&[Home]) -> bool) -> bool {
130	    schema().iter().any(|key| {
131	        if !home_pred(key.homes) {
132	            return false;
133	        }
134	        if !key.dynamic {
135	            return key.path == actual;
136	        }
137	        let entry_segs: Vec<&str> = key.path.split('.').collect();
138	        let actual_segs: Vec<&str> = actual.split('.').collect();
139	        entry_segs.len() == actual_segs.len()
140	            && entry_segs
141	                .iter()
142	                .zip(actual_segs.iter())
143	                .all(|(e, a)| e == a || (e.starts_with('<') && e.ends_with('>')))
144	    })
145	}
146	
147	/// Validate one config file against the schema, filtered to the
148	/// homes accepted at that file by `home_pred`.
149	///
150	/// - A missing file is not an error — `info!`s that it's absent
151	///   and returns `Ok(0)`.
152	/// - Each key not recognized by `key_known` is reported with
153	///   `warn!`, naming `label` and the key; keys are checked in
154	///   sorted order for stable output.
155	/// - Returns the count of unknown keys found. A load error
156	///   (malformed TOML) propagates as `Err`.
157	fn validate_file(
158	    path: &std::path::Path,
159	    label: &str,
160	    home_pred: impl Fn(&[Home]) -> bool,
161	) -> Result<usize, Box<dyn Error>> {
162	    if !path.exists() {
163	        info!("{label}: {} not found — skipping", path.display());
164	        return Ok(0);
165	    }
166	    let map = toml_load(path)?;
167	    let mut keys: Vec<&String> = map.keys().collect();
168	    keys.sort();
169	
170	    let mut unknown = 0;
171	    for key in keys {
172	        if !key_known(key, &home_pred) {
173	            warn!("{label} ({}): unknown key {key:?}", path.display());
174	            unknown += 1;
175	        }
176	    }
177	    Ok(unknown)
178	}
179	
180	/// Validate the selected home(s)' config file(s) against the
181	/// schema, returning the total count of unknown keys.
182	fn validate(params: &ConfigParams) -> Result<usize, Box<dyn Error>> {
183	    let mut unknown = 0;
184	
185	    if matches!(params.home, HomeFilter::User | HomeFilter::All) {
186	        unknown += validate_file(&config_path()?, "user config", |homes| {
187	            homes.contains(&Home::User)
188	        })?;
189	    }
190	
191	    if matches!(params.home, HomeFilter::Workspace | HomeFilter::All) {
192	        match find_workspace_root() {
193	            Some(root) => {
194	                unknown +=
195	                    validate_file(&root.join(VC_CONFIG_FILE), "workspace config", |homes| {
196	                        homes.contains(&Home::WorkspaceCode) || homes.contains(&Home::WorkspaceBot)
197	                    })?;
198	            }
199	            None => info!("workspace config: not inside a workspace — skipping"),
200	        }
201	    }
202	
203	    Ok(unknown)
204	}
205	
206	/// Print the settable config schema, grouped by config home then
207	/// TOML section (`--home` selects which home group(s) to print),
208	/// or — with `--validate` — check the config file(s) for unknown
209	/// keys and exit non-zero if any are found.
210	pub fn config(_ctx: &Context, params: &ConfigParams) -> Result<(), Box<dyn std::error::Error>> {
211	    if params.validate {
212	        let total = validate(params)?;
213	        return if total > 0 {
214	            Err(format!("config: {total} unknown key(s) found").into())
215	        } else {
216	            info!("config: all keys recognized");
217	            Ok(())
218	        };
219	    }
220	
221	    info!(
222	        "# vc-x1 settable config keys (from vc-x1 {})",
223	        env!("CARGO_PKG_VERSION")
224	    );
225	    info!("# Keys below are shown at their built-in default (commented");
226	    info!("# unless required); run `vc-x1 config --validate` to check a");
227	    info!("# config file's keys against this schema.");
228	    info!("");
229	
230	    let all_keys = schema();
231	
232	    if matches!(params.home, HomeFilter::User | HomeFilter::All) {
233	        let user_keys: Vec<&ConfigKey> = all_keys.iter().filter(|k| in_user_group(k)).collect();
234	        print_group("User", "~/.config/vc-x1/config.toml", &user_keys);
235	    }
236	
237	    if matches!(params.home, HomeFilter::Workspace | HomeFilter::All) {
238	        let workspace_keys: Vec<&ConfigKey> =
239	            all_keys.iter().filter(|k| in_workspace_group(k)).collect();
240	        print_group("Workspace", "<root>/.vc-config.toml", &workspace_keys);
241	    }
242	
243	    Ok(())
244	}
