1	//! Single source of truth for every settable config key across
2	//! vc-x1's two config homes (the user config file and the
3	//! per-repo workspace config).
4	//!
5	//! - `crate::config_cmd` prints this registry as an annotated
6	//!   schema, and — with `--validate` — checks a config file's keys
7	//!   against it (dynamic-segment aware).
8	//! - `crate::init` derives init's commented defaults from
9	//!   `schema()`, so these surfaces cannot drift from this list.
10	
11	/// Which config home a key belongs to.
12	/// - `User` — `~/.config/vc-x1/config.toml`
13	/// - `WorkspaceCode` / `WorkspaceBot` — `<root>/.vc-config.toml`
14	///   in the work repo vs the `.claude` bot repo
15	#[derive(Debug, Clone, Copy, PartialEq, Eq)]
16	pub enum Home {
17	    User,
18	    WorkspaceCode,
19	    WorkspaceBot,
20	}
21	
22	/// The value shape a key expects (for rendering / future typed
23	/// use).
24	#[derive(Debug, Clone, Copy, PartialEq, Eq)]
25	pub enum ValueKind {
26	    Str,
27	    Usize,
28	    ItemList,
29	}
30	
31	/// One settable configuration key.
32	pub struct ConfigKey {
33	    /// The config key (TOML table and key joined by `.`), e.g.
34	    /// `"bot-session.col-width"`.
35	    pub path: &'static str,
36	    /// Which home(s) accept this key.
37	    pub homes: &'static [Home],
38	    /// The value shape this key expects.
39	    pub kind: ValueKind,
40	    /// Rendered default, `None` if there is no default.
41	    pub default: Option<&'static str>,
42	    /// Active (not commented) in init; the value is role-specific.
43	    pub required: bool,
44	    /// The path has a `<placeholder>` segment matching a family
45	    /// of keys (e.g. `repo.category.<cat>`).
46	    pub dynamic: bool,
47	    /// One-line description.
48	    pub doc: &'static str,
49	    /// The command/flag or structural context this key is
50	    /// associated with (e.g. `"bot-session --col-width"`).
51	    pub used_by: &'static str,
52	    /// A representative example value for keys with no default;
53	    /// rendered on the assignment line, marked `# example`,
54	    /// instead of a bare placeholder. `None` when the key has a
55	    /// real default (the default serves as the example).
56	    pub example: Option<&'static str>,
57	}
58	
59	/// Homes accepted by every `bot-session.*` key: all three homes,
60	/// since the user config and both workspace configs may each
61	/// carry a default.
62	const BOT_SESSION_HOMES: &[Home] = &[Home::User, Home::WorkspaceCode, Home::WorkspaceBot];
63	
64	/// Homes accepted by workspace-only keys (`workspace.*`,
65	/// `push.*`): the two `.vc-config.toml` homes, never the user
66	/// config.
67	const WORKSPACE_HOMES: &[Home] = &[Home::WorkspaceCode, Home::WorkspaceBot];
68	
69	/// The complete registry of settable keys.
70	///
71	/// - User home: `default.*`, `repo.*`, and the per-account
72	///   `account.<name>.repo.*` family.
73	/// - `bot-session.*`: accepted in all three homes.
74	/// - Workspace-only: `workspace.*`, `push.*`.
75	const SCHEMA: &[ConfigKey] = &[
76	    ConfigKey {
77	        path: "default.account",
78	        homes: &[Home::User],
79	        kind: ValueKind::Str,
80	        default: None,
81	        required: false,
82	        dynamic: false,
83	        doc: "Account profile (an [account.<name>] section) to use when --account is absent",
84	        used_by: "--account (init and account-aware commands)",
85	        example: Some("work"),
86	    },
87	    ConfigKey {
88	        path: "default.debug",
89	        homes: &[Home::User],
90	        kind: ValueKind::Str,
91	        default: None,
92	        required: false,
93	        dynamic: false,
94	        doc: "Default --debug value when used without an argument (reserved; not yet consumed)",
95	        used_by: "--debug (reserved; not yet consumed)",
96	        example: Some("true"),
97	    },
98	    ConfigKey {
99	        path: "repo.default",
100	        homes: &[Home::User],
101	        kind: ValueKind::Str,
102	        default: None,
103	        required: false,
104	        dynamic: false,
105	        doc: "Default repo category when --repo is bare — a [repo.category.<cat>] name: a built-in (remote, local) or your own",
106	        used_by: "--repo (default category when --repo is bare)",
107	        example: Some("acmehousing"),
108	    },
109	    ConfigKey {
110	        path: "repo.category.<cat>",
111	        homes: &[Home::User],
112	        kind: ValueKind::Str,
113	        default: None,
114	        required: false,
115	        dynamic: true,
116	        doc: "Literal value for repo category <cat> — a remote URL prefix (init appends /<NAME>.git) or a local parent dir",
117	        used_by: "--repo <cat> (init remote/local resolution)",
118	        example: Some("git@github.com:acmehousing"),
119	    },
120	    ConfigKey {
121	        path: "account.<name>.repo.default",
122	        homes: &[Home::User],
123	        kind: ValueKind::Str,
124	        default: None,
125	        required: false,
126	        dynamic: true,
127	        doc: "Per-account default repo category — a [repo.category.<cat>] name: a built-in (remote, local) or your own",
128	        used_by: "--account <name> with --repo",
129	        example: Some("acmehousing"),
130	    },
131	    ConfigKey {
132	        path: "account.<name>.repo.category.<cat>",
133	        homes: &[Home::User],
134	        kind: ValueKind::Str,
135	        default: None,
136	        required: false,
137	        dynamic: true,
138	        doc: "Per-account literal value for repo category <cat> (remote URL prefix or local parent dir)",
139	        used_by: "--account <name> with --repo <cat>",
140	        example: Some("git@github.com:acmehousing"),
141	    },
142	    ConfigKey {
143	        path: "bot-session.items",
144	        homes: BOT_SESSION_HOMES,
145	        kind: ValueKind::ItemList,
146	        default: Some("headers,user,assistant,tool,summary"),
147	        required: false,
148	        dynamic: false,
149	        doc: "Default bot-session item set (comma-separated)",
150	        used_by: "bot-session --<item> / --no-<item> / --all / --none",
151	        example: None,
152	    },
153	    ConfigKey {
154	        path: "bot-session.result-lines",
